import { useState, useEffect } from "react";
import "./Tasks.css";

export default function Tasks() {
  const [tasks, setTasks] = useState([]);
  const [newTask, setNewTask] = useState("");
  const [editingId, setEditingId] = useState(null);

  useEffect(() => {
    const saved = JSON.parse(localStorage.getItem("tasks")) || [];
    setTasks(saved);
  }, []);

  useEffect(() => {
    localStorage.setItem("tasks", JSON.stringify(tasks));
  }, [tasks]);

  const addTask = (status) => {
    if (!newTask.trim()) return;

    const task = {
      id: Date.now(),
      title: newTask,
      status,
    };

    setTasks([...tasks, task]);
    setNewTask("");
  };

  const updateStatus = (id, newStatus) => {
    setTasks(tasks.map(t =>
      t.id === id ? { ...t, status: newStatus } : t
    ));
  };
  const updateTitle = (id, value) => {
    setTasks(tasks.map(t =>
      t.id === id ? { ...t, title: value } : t
    ));
  };

  return (
    <div className="kanban-container">

      {["todo", "progress", "done"].map((status) => (
        <div key={status} className="kanban-column">

          <h3>
            {status === "todo" && "⚪ Not Started"}
            {status === "progress" && "🔵 In Progress"}
            {status === "done" && "🟢 Done"}
          </h3>

          {tasks
            .filter(t => (t.status || "todo") === status)
            .map(t => (
              <div key={t.id} className="task-card">

                {editingId === t.id ? (
                  <input
                    value={t.title}
                    onChange={(e) => updateTitle(t.id, e.target.value)}
                    onBlur={() => setEditingId(null)}
                    autoFocus
                  />
                ) : (
                  <p
                    onClick={(e) => {
                      e.stopPropagation(); 
                      setEditingId(t.id);
                    }}
                  >
                    {t.title}
                  </p>
                )}

                <div className="actions">
                  {status !== "todo" && (
                    <span
                      onClick={(e) => {
                        e.stopPropagation(); 
                        updateStatus(t.id, "todo");
                      }}
                    >
                      ←
                    </span>
                  )}

                  {status !== "done" && (
                    <span
                      onClick={(e) => {
                        e.stopPropagation(); 
                        updateStatus(t.id, "done");
                      }}
                    >
                      →
                    </span>
                  )}
                </div>

              </div>
            ))}
          <input
            placeholder="+ Add a task"
            value={newTask}
            onChange={(e) => setNewTask(e.target.value)}
            onKeyDown={(e) => e.key === "Enter" && addTask(status)}
          />

        </div>
      ))}

    </div>
  );
}
